select count(*) from company
and (com_name like '%' || #{keyword} || '%' or biz_no like '%' || #{keyword} || '%')
and industry_grp_code = #{industryGrpCode}

mapper.update:
update company
set com_name = #{comName}
    ,com_ceo = #{comCeo}
    ,industry_grp_code = #{industryGrpCode}
